15	interface QuoteResult {
16	  premium: number;
17	}
18	
19	const PROCESSING_FEE = 5;
20	const FIRST_INSURANCE_RATE = 0.1;
21	
22	const BASE_PREMIUM: Record<string, number> = {
23	  sword: 100,
24	  amulet: 60,
25	  staff: 80,
26	  potion: 40,
27	  rune: 25,
28	};
29	
30	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
31	const BLOCK_SIZE = 3;
32	const BLOCK_BASE_PREMIUM = 60;
33	
34	const itemsBaseForType = (type: string, count: number): number => {
35	  if (COMPONENT_TYPES.has(type) && count === BLOCK_SIZE) return BLOCK_BASE_PREMIUM;
36	  return count * BASE_PREMIUM[type];
37	};
38	
39	const countByType = (items: Item[]): Map<string, number> =>
40	  items.reduce(
41	    (counts, item) => counts.set(item.type, (counts.get(item.type) ?? 0) + 1),
42	    new Map<string, number>(),
43	  );
44	
45	const policyBase = (items: Item[]): number => {
46	  let total = 0;
47	  for (const [type, count] of countByType(items)) total += itemsBaseForType(type, count);
48	  return total;
49	};
50	
51	const quoteStep = (step: QuoteStep): QuoteResult => {
52	  const base = policyBase(step.items);
53	  const firstInsurance = base * FIRST_INSURANCE_RATE;
54	  return { premium: Math.ceil(base + firstInsurance + PROCESSING_FEE) };
55	};
56	
57	export const processScenario = (scenario: Scenario): { results: QuoteResult[] } => {
58	  const results = scenario.steps.map(quoteStep);
59	  return { results };
60	};
